import * as z from "zod";

export const vehicleSchema = z.object({
  registrationNo: z.string().min(2, "Registration number must be at least 2 characters").max(20, "Registration number is too long"),
  name: z.string().min(2, "Vehicle name is required"),
  type: z.enum(["VAN", "TRUCK", "MINI"]),
  capacityKg: z.coerce.number().positive("Capacity must be greater than 0"),
  odometer: z.coerce.number().min(0, "Odometer cannot be negative"),
  acquisitionCost: z.coerce.number().min(0, "Cost cannot be negative"),
  region: z.string().min(2, "Region is required"),
  status: z.enum(["available", "on_trip", "in_shop", "retired"]).default("available"),
});

export type VehicleFormValues = z.infer<typeof vehicleSchema>;

export const driverSchema = z.object({
  name: z.string().min(2, "Driver name is required"),
  licenseNumber: z.string().min(4, "License number must be at least 4 characters"),
  category: z.enum(["LMV", "HMV"]),
  licenseExpiry: z.coerce.date().refine((date) => date > new Date(), {
    message: "License is already expired",
  }),
  contact: z.string().min(10, "Valid phone number is required"),
  status: z.enum(["available", "on_trip", "off_duty", "suspended"]).default("available"),
});

export type DriverFormValues = z.infer<typeof driverSchema>;
